1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_MULTIPLIER = 1.1;
3	
4	type Item = { type: string; cursed?: boolean; enchantment?: number };
5	const CURSE_SURCHARGE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	type QuoteStep = { op: "quote"; items: Item[] };
9	type Step = QuoteStep;
10	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
22	
23	const roundUp = (n: number): number => Math.ceil(Math.round(n * 1e6) / 1e6);
24	
25	const BLOCK_BASE = 60;
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	const countByType = (items: Item[]): Record<string, number> => {
29	  const counts: Record<string, number> = {};
30	  for (const item of items) {
31	    counts[item.type] = (counts[item.type] ?? 0) + 1;
32	  }
33	  return counts;
34	};
35	
36	const groupBasePrice = (type: string, count: number): number => {
37	  const lineTotal = basePremium({ type }) * count;
38	  const blockApplies = COMPONENT_TYPES.has(type) && count === 3;
39	  return blockApplies ? BLOCK_BASE : lineTotal;
40	};
41	
42	const itemBaseTotal = (items: Item[]): number =>
43	  Object.entries(countByType(items)).reduce(
44	    (sum, [type, count]) => sum + groupBasePrice(type, count),
45	    0,
46	  );
47	
48	const itemSurchargeRate = (item: Item): number => {
49	  let rate = 0;
50	  if (item.cursed) rate += CURSE_SURCHARGE;
51	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE;
52	  return rate;
53	};
54	
55	const itemSurcharges = (items: Item[]): number =>
56	  items.reduce((sum, item) => sum + basePremium(item) * itemSurchargeRate(item), 0);
57	
58	const quotePremium = (items: Item[]): number => {
59	  const beforeFee =
60	    itemBaseTotal(items) * FIRST_INSURANCE_MULTIPLIER + itemSurcharges(items);
61	  return roundUp(beforeFee + PROCESSING_FEE);
62	};
63	
64	export const run = (scenario: Scenario): { results: { premium: number }[] } => {
65	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
66	  return { results };
67	};
